import React, { useState } from "react";
import CalendarGrid from "./CalendarGrid";
import events from "../data/events";
import "./Calendar.css";

const Calendar = () => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [view, setView] = useState("month"); // "month" | "week"

  // -----------------------
  // Helper functions
  // -----------------------
  const getMonthYearLabel = () => {
    return currentDate.toLocaleString("default", {
      month: "long",
      year: "numeric",
    });
  };

  // -----------------------
  // Navigation
  // -----------------------
  const handlePrev = () => {
    const newDate = new Date(currentDate);

    if (view === "month") {
      newDate.setMonth(newDate.getMonth() - 1);
    } else {
      newDate.setDate(newDate.getDate() - 7);
    }

    setCurrentDate(newDate);
  };

  const handleNext = () => {
    const newDate = new Date(currentDate);

    if (view === "month") {
      newDate.setMonth(newDate.getMonth() + 1);
    } else {
      newDate.setDate(newDate.getDate() + 7);
    }

    setCurrentDate(newDate);
  };

  // -----------------------
  // View switch
  // -----------------------
  const showMonthView = () => setView("month");
  const showWeekView = () => setView("week");

  return (
    <div className="calendar-wrapper">
      {/* Header */}
      <div className="calendar-header">
        {/* Left */}
        <div className="calendar-header-left">
          <button className="btn black" onClick={showMonthView}>
            Month
          </button>
        </div>

        {/* Center */}
        <div className="calendar-header-center">
          <button className="btn green" onClick={handlePrev}>
            Prev
          </button>

          <span className="calendar-title">
            {getMonthYearLabel()}
          </span>

          <button className="btn green" onClick={handleNext}>
            Next
          </button>
        </div>

        {/* Right */}
        <div className="calendar-header-right">
          <button className="btn green" onClick={showWeekView}>
            Week
          </button>
        </div>
      </div>

      {/* Grid */}
      <CalendarGrid
        currentDate={currentDate}
        view={view}
        events={events}
      />
    </div>
  );
};

export default Calendar;
